sql:
SELECT maintenance_type, AVG(cost) AS avg_cost
FROM road_maintenance
GROUP BY maintenance_type;

SELECT signal_status
FROM traffic_signals
WHERE signal_id = 1;

SELECT COUNT(*) AS roads_under_construction
FROM road_conditions
WHERE condition_status = 'under construction';

SELECT maintenance_date, cost
FROM road_maintenance
WHERE quality_rating = 'excellent';

SELECT SUM(cost) AS total_cost
FROM road_maintenance
WHERE road_type_id = 1;

SELECT type_name, total_length_km
FROM road_types
WHERE road_type_id = 1;

SELECT condition_status
FROM road_conditions
WHERE condition_id = 1;

SELECT SUM(total_length_km) AS total_length
FROM road_types
WHERE type_name = 'highway.motorway';

external_knowledge:
- Maintenance details include the date, cost, type, estimated completion date, actual completion date, and quality rating of the latest maintenance activity for each road type;
- Current road conditions include the status, inspection frequency, inspector, emergency status, and estimated repair time of the latest condition check for each road type;
- Recent traffic signal statuses include the type, status, last maintenance date, and next maintenance date of the latest traffic signal for each road type.
